import React from 'react';

import { Button, Image, SearchInput } from 'components';

import { Hamburger } from './components';
import { State } from './Header.types';
import styles from './Header.module.scss';

export class Header extends React.Component<{}, State> {
  state: State = { isMobileMenuOpened: false };

  // Component lifecycle methods

  componentDidUpdate() {
    const { isMobileMenuOpened } = this.state;
    document.getElementById('root')!.classList[isMobileMenuOpened ? 'add' : 'remove']('no-scroll');
  }

  // Action handlers

  toggleMobileMenu = (): void => {
    this.setState((prevState: State) => ({ isMobileMenuOpened: !prevState.isMobileMenuOpened }));
  };

  closeMobileMenu = (): void => {
    this.setState({ isMobileMenuOpened: false });
  };

  // RENDER

  render() {
    const { isMobileMenuOpened } = this.state;

    return (
      <header className={styles.header}>
        <div className={styles.title} onClick={() => console.log('redirect to Home page')}>
          <Image src="images/application_logo.png" alt="Poku Art Challenge logo" pixelRatio={2} />
          <span>Poku Art Challenge</span>
        </div>

        <SearchInput className={styles.search} placeholder="search" />

        <Hamburger active={isMobileMenuOpened} onClick={this.toggleMobileMenu} />

        <Button
          color="transparent"
          onClick={() => console.log('login user')}
          className={styles.login_button}
        >
          Log in
        </Button>
      </header>
    );
  }
}
